GUICommonActivityRewardItem = class("GUICommonActivityRewardItem", IGUIWindow) ---@class GUICommonActivityRewardItem : IGUIWindow

function GUICommonActivityRewardItem:onLoad(parent)
    self.parent = parent
    self.llRoot = DynamicCast.dynamicCastWindow(GUIType.Layout, self.root)
    self.ivIcon = self:getChildWindowByName("CommonActivityRewardItem-Icon", GUIType.StaticImage)
    self.ivBg = self:getChildWindowByName("CommonActivityRewardItem-Bg", GUIType.StaticImage)
    self.ivSelect = self:getChildWindowByName("CommonActivityRewardItem-Select", GUIType.StaticImage)
    self.ivEffect = self:getChildWindowByName("CommonActivityRewardItem-Effect", GUIType.StaticImage)
    self.tvNum = self:getChildWindowByName("CommonActivityRewardItem-Num", GUIType.StaticText)
    self.tvName = self:getChildWindowByName("CommonActivityRewardItem-Name", GUIType.StaticText)
    self.llRoot:registerEvent(GUIEvent.Click, function()
        if self.parent then
            self.parent:selectItem(self)
        end
    end)
    self.ivSelect:SetVisible(false)
    self.ivEffect:SetVisible(false)
end

function GUICommonActivityRewardItem:setRewardData(data)
    UIHelper:setImageAdjustSize(self.ivIcon, data.image)
    self.reward = data
    if not data.numLang or data.numLang == "#" then
        self.tvNum:SetText("x" .. data.num)
    else
        self.tvNum:SetText(Lang:getString(data.numLang))
    end

    if data.effect ~= "#" then
        self.ivEffect:SetEffectName(data.effect)
        self.ivEffect:SetVisible(true)
    end
    self.ivBg:SetImage("set:common_activity.json image:img_iconboard_" .. data.quality)
end

---播放显示动画并显示特效
function GUICommonActivityRewardItem:setLotteryResult(data)
    if data.effect ~= "#" then
        self.ivEffect:SetEffectName(data.effect)
    end
    self.ivEffect:SetVisible(true)

    local scale = 0
    self.ivIcon:SetArea({ 0, 0 }, { 0, 0 }, { scale, 0 }, { scale, 0 })
    self.ivBg:SetArea({ 0, 0 }, { 0, 0 }, { scale, 0 }, { scale, 0 })
    self.ivEffect:SetArea({ 0, 0 }, { -(scale / 2), 0 }, { scale, 0 }, { scale, 0 })

    self:addTimer(LuaTimer:scheduleTimer(function()
        self.ivIcon:SetArea({ 0, 0 }, { 0, 0 }, { math.min(scale, 0.9), 0 }, { math.min(scale, 0.9), 0 })
        self.ivBg:SetArea({ 0, 0 }, { 0, 0 }, { scale, 0 }, { scale, 0 })
        self.ivEffect:SetArea({ 0, 0 }, { -(scale / 2), 0 }, { scale, 0 }, { scale, 0 })
        scale = scale + 0.05
        UIHelper:setImageAdjustSize(self.ivIcon, data.image)
    end, 8, 20))

    if not data.numLang or data.numLang == "#" then
        self.tvNum:SetText(data.num)
    else
        self.tvNum:SetText(Lang:getString(data.numLang))
    end
    self.ivBg:SetImage("set:common_activity.json image:img_iconboard_" .. data.quality)
end

---播放显示动画并显示特效
